import React, { useState, useEffect } from 'react';
import { adminService } from '../services/api';
import { ShoppingCart, TrendingUp, DollarSign, Award } from 'lucide-react';

function AdminDashboard() {
  const [stats, setStats] = useState(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    loadDashboard();
  }, []);

  const loadDashboard = async () => {
    try {
      const response = await adminService.getDashboard();
      setStats(response.data);
      setLoading(false);
    } catch (error) {
      console.error('Error loading dashboard:', error);
      setLoading(false);
    }
  };

  const formatCurrency = (amount) => {
    return new Intl.NumberFormat('en-IN', {
      style: 'currency',
      currency: 'INR',
      maximumFractionDigits: 0
    }).format(amount);
  };

  if (loading) {
    return (
      <div style={{
        display: 'flex',
        justifyContent: 'center',
        alignItems: 'center',
        minHeight: '100vh',
        fontSize: '1.2rem',
        color: '#64748b'
      }}>
        Loading dashboard...
      </div>
    );
  }

  if (!stats) {
    return (
      <div style={{
        display: 'flex',
        justifyContent: 'center',
        alignItems: 'center',
        minHeight: '100vh',
        fontSize: '1.2rem',
        color: '#64748b'
      }}>
        No data available
      </div>
    );
  }

  return (
    <div style={{
      padding: '2rem',
      background: '#f8fafc',
      minHeight: '100vh'
    }}>
      {/* Header */}
      <div style={{ marginBottom: '3rem' }}>
        <h1 style={{
          fontSize: '2.5rem',
          fontWeight: '700',
          background: 'linear-gradient(135deg, #667eea 0%, #764ba2 100%)',
          WebkitBackgroundClip: 'text',
          WebkitTextFillColor: 'transparent',
          marginBottom: '0.5rem'
        }}>
          Admin Dashboard
        </h1>
        <p style={{
          fontSize: '1.1rem',
          color: '#64748b'
        }}>
          Welcome back! Here's your business overview
        </p>
      </div>

      {/* Stats Grid */}
      <div style={{
        display: 'grid',
        gridTemplateColumns: 'repeat(auto-fit, minmax(280px, 1fr))',
        gap: '2rem'
      }}>
        {/* Total Products */}
        <div style={{
          background: 'linear-gradient(135deg, #667eea 0%, #764ba2 100%)',
          borderRadius: '20px',
          padding: '2rem',
          color: 'white',
          boxShadow: '0 10px 40px rgba(102, 126, 234, 0.3)',
          transition: 'transform 0.3s ease, box-shadow 0.3s ease',
          cursor: 'pointer'
        }}
        onMouseEnter={(e) => {
          e.currentTarget.style.transform = 'translateY(-8px)';
          e.currentTarget.style.boxShadow = '0 20px 60px rgba(102, 126, 234, 0.4)';
        }}
        onMouseLeave={(e) => {
          e.currentTarget.style.transform = 'translateY(0)';
          e.currentTarget.style.boxShadow = '0 10px 40px rgba(102, 126, 234, 0.3)';
        }}
        >
          <div style={{
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'space-between',
            marginBottom: '1rem'
          }}>
            <div style={{
              background: 'rgba(255, 255, 255, 0.2)',
              borderRadius: '12px',
              padding: '0.75rem',
              backdropFilter: 'blur(10px)'
            }}>
              <ShoppingCart size={28} />
            </div>
          </div>
          <div>
            <p style={{
              fontSize: '0.9rem',
              opacity: 0.9,
              marginBottom: '0.5rem',
              fontWeight: '500',
              letterSpacing: '0.5px'
            }}>
              Total Products
            </p>
            <p style={{
              fontSize: '3rem',
              fontWeight: '700',
              lineHeight: 1
            }}>
              {stats.totalProducts}
            </p>
          </div>
        </div>

        {/* Total Sales */}
        <div style={{
          background: 'linear-gradient(135deg, #f093fb 0%, #f5576c 100%)',
          borderRadius: '20px',
          padding: '2rem',
          color: 'white',
          boxShadow: '0 10px 40px rgba(240, 147, 251, 0.3)',
          transition: 'transform 0.3s ease, box-shadow 0.3s ease',
          cursor: 'pointer'
        }}
        onMouseEnter={(e) => {
          e.currentTarget.style.transform = 'translateY(-8px)';
          e.currentTarget.style.boxShadow = '0 20px 60px rgba(240, 147, 251, 0.4)';
        }}
        onMouseLeave={(e) => {
          e.currentTarget.style.transform = 'translateY(0)';
          e.currentTarget.style.boxShadow = '0 10px 40px rgba(240, 147, 251, 0.3)';
        }}
        >
          <div style={{
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'space-between',
            marginBottom: '1rem'
          }}>
            <div style={{
              background: 'rgba(255, 255, 255, 0.2)',
              borderRadius: '12px',
              padding: '0.75rem',
              backdropFilter: 'blur(10px)'
            }}>
              <TrendingUp size={28} />
            </div>
          </div>
          <div>
            <p style={{
              fontSize: '0.9rem',
              opacity: 0.9,
              marginBottom: '0.5rem',
              fontWeight: '500',
              letterSpacing: '0.5px'
            }}>
              Total Sales
            </p>
            <p style={{
              fontSize: '3rem',
              fontWeight: '700',
              lineHeight: 1
            }}>
              {stats.totalSales}
            </p>
          </div>
        </div>

        {/* Total Revenue */}
        <div style={{
          background: 'linear-gradient(135deg, #4facfe 0%, #00f2fe 100%)',
          borderRadius: '20px',
          padding: '2rem',
          color: 'white',
          boxShadow: '0 10px 40px rgba(79, 172, 254, 0.3)',
          transition: 'transform 0.3s ease, box-shadow 0.3s ease',
          cursor: 'pointer'
        }}
        onMouseEnter={(e) => {
          e.currentTarget.style.transform = 'translateY(-8px)';
          e.currentTarget.style.boxShadow = '0 20px 60px rgba(79, 172, 254, 0.4)';
        }}
        onMouseLeave={(e) => {
          e.currentTarget.style.transform = 'translateY(0)';
          e.currentTarget.style.boxShadow = '0 10px 40px rgba(79, 172, 254, 0.3)';
        }}
        >
          <div style={{
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'space-between',
            marginBottom: '1rem'
          }}>
            <div style={{
              background: 'rgba(255, 255, 255, 0.2)',
              borderRadius: '12px',
              padding: '0.75rem',
              backdropFilter: 'blur(10px)'
            }}>
              <DollarSign size={28} />
            </div>
          </div>
          <div>
            <p style={{
              fontSize: '0.9rem',
              opacity: 0.9,
              marginBottom: '0.5rem',
              fontWeight: '500',
              letterSpacing: '0.5px'
            }}>
              Total Revenue
            </p>
            <p style={{
              fontSize: '2rem',
              fontWeight: '700',
              lineHeight: 1
            }}>
              {formatCurrency(stats.totalRevenue)}
            </p>
          </div>
        </div>

        {/* Commission Paid */}
        <div style={{
          background: 'linear-gradient(135deg, #fa709a 0%, #fee140 100%)',
          borderRadius: '20px',
          padding: '2rem',
          color: 'white',
          boxShadow: '0 10px 40px rgba(250, 112, 154, 0.3)',
          transition: 'transform 0.3s ease, box-shadow 0.3s ease',
          cursor: 'pointer'
        }}
        onMouseEnter={(e) => {
          e.currentTarget.style.transform = 'translateY(-8px)';
          e.currentTarget.style.boxShadow = '0 20px 60px rgba(250, 112, 154, 0.4)';
        }}
        onMouseLeave={(e) => {
          e.currentTarget.style.transform = 'translateY(0)';
          e.currentTarget.style.boxShadow = '0 10px 40px rgba(250, 112, 154, 0.3)';
        }}
        >
          <div style={{
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'space-between',
            marginBottom: '1rem'
          }}>
            <div style={{
              background: 'rgba(255, 255, 255, 0.2)',
              borderRadius: '12px',
              padding: '0.75rem',
              backdropFilter: 'blur(10px)'
            }}>
              <Award size={28} />
            </div>
          </div>
          <div>
            <p style={{
              fontSize: '0.9rem',
              opacity: 0.9,
              marginBottom: '0.5rem',
              fontWeight: '500',
              letterSpacing: '0.5px'
            }}>
              Commission Paid
            </p>
            <p style={{
              fontSize: '2rem',
              fontWeight: '700',
              lineHeight: 1
            }}>
              {formatCurrency(stats.totalCommissionPaid)}
            </p>
          </div>
        </div>
      </div>
    </div>
  );
}

export default AdminDashboard;
